module RefModule(
    input clk,
    input rst,
    input up_down,
    output reg [2:0] count
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk) begin
        if (rst)
            count <= 3'b000;
        else if (up_down)
            count <= count + 1;
        else
            count <= count - 1;
    end

endmodule
